// // This module decrements a 3-bit binary counter on each positive clock edge and resets to seven when the reset signal is asserted.
module top_module(input clk , input reset , output q);reg [2:0] count;
assign q = count[0];

always @(posedge clk ,posedge reset)
begin
	if(reset)
		count <= 3'b000;
	else
		count <= count + 1;
end

endmodule
